// Generate idempotency key
const input = $input.first().json;
const body = input.body || input;

const required = ['provider_id', 'service_id', 'start_time'];
for (const f of required) {
  if (!body[f]) {
    return [{ json: { error: 'Missing: ' + f } }];
  }
}

const idempotencyKey = `booking_${body.provider_id}_${body.service_id}_${body.start_time}_${body.customer_id || 'anon'}`;
const sanitizedKey = idempotencyKey.replace(/[^a-zA-Z0-9_:-]/g, '_').substring(0, 255);

return [{
  json: {
    step: 2,
    provider_id: body.provider_id,
    service_id: body.service_id,
    start_time: body.start_time,
    idempotency_key: sanitizedKey
  }
}];

// Return result
const dbResult = $input.first().json;

return [{
  json: {
    step: 3,
    db_result: dbResult,
    message: 'Postgres working - Step 3 complete'
  }
}];
